export const meta = {
  name: 'qa-csrf',
  description: 'QA workflow: CSRF protection in Nablarch web application',
  phases: [
    { title: 'Semantic Search', detail: 'Search knowledge files for CSRF-related content' },
    { title: 'Read Sections', detail: 'Read selected section content' },
    { title: 'Generate Answer', detail: 'Generate and verify Japanese answer' }
  ]
}

const SCHEMA_SEARCH = {
  type: 'object',
  properties: {
    selected_pages: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          path: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['path', 'reason']
      }
    },
    excluded_pages: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          path: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['path', 'reason']
      }
    },
    selected_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          section_id: { type: 'string' },
          relevance: { type: 'string', enum: ['high', 'partial'] },
          reason: { type: 'string' }
        },
        required: ['file', 'section_id', 'relevance', 'reason']
      }
    },
    excluded_sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          file: { type: 'string' },
          section_id: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['file', 'section_id', 'reason']
      }
    }
  },
  required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
}

phase('Semantic Search')
const searchResult = await agent(
  `You are executing the semantic search workflow for the nabledge-6 skill.

## Task
Execute the semantic search described in workflows/semantic-search.md for the following query:

Query: "外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）"

## Knowledge Base Location
The knowledge files are at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

## Your Steps
1. Read the semantic search workflow at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/workflows/semantic-search.md
2. Follow the workflow to find relevant knowledge pages and sections
3. For each page you consider, record why it was selected or skipped
4. For each section within selected pages, record why it was selected (high/partial) or skipped
5. Return the structured result

Return a JSON object with:
- selected_pages: array of {path, reason} for pages selected for further examination
- excluded_pages: array of {path, reason} for pages explicitly considered but excluded
- selected_sections: array of {file, section_id, relevance (high|partial), reason} 
- excluded_sections: array of {file, section_id, reason} for sections within selected pages that were not chosen`,
  { schema: SCHEMA_SEARCH }
)

log(`Semantic search complete: ${searchResult.selected_sections.length} sections selected`)

phase('Read Sections')
// Select up to 10 sections: high first, then partial
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)
const readArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`)

const sectionsContent = await agent(
  `Run the following bash command and return the complete output verbatim.

Command:
bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${readArgs.join(' ')}

Return the complete stdout output of this command. Do not summarize or truncate.`,
  {}
)

log(`Sections read: ${sectionsToRead.length} sections`)

phase('Generate Answer')
const SCHEMA_ANSWER = {
  type: 'object',
  properties: {
    answer_text: { type: 'string' },
    verify_result: { type: 'string', enum: ['PASS', 'FAIL'] },
    issues: { type: 'array', items: { type: 'string' } },
    final_answer: { type: 'string' },
    answer_sections_used: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          ref: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['ref', 'reason']
      }
    },
    answer_sections_unused: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          ref: { type: 'string' },
          reason: { type: 'string' }
        },
        required: ['ref', 'reason']
      }
    }
  },
  required: ['answer_text', 'verify_result', 'final_answer', 'answer_sections_used', 'answer_sections_unused']
}

const answerResult = await agent(
  `You are answering a Nablarch question in Japanese based on knowledge sections.

## Question
外部サイトから不正にPOSTされるのを防ぎたい。NablarchにCSRF対策の仕組みはある？どう設定する？（処理方式: ウェブアプリケーション）（目的: セキュリティ対応したい）

## Sections Content
${sectionsContent}

## Read Sections
${sectionsToRead.map(s => s.file + ':' + s.section_id).join(', ')}

## Step 5: Generate answer
If sections_content is empty, set answer_text to "この情報は知識ファイルに含まれていません。"

Otherwise, generate a Japanese answer following these steps:
1. Read all sections in sections_content.
2. Focus on approaches that match ウェブアプリケーション processing type.
3. Identify the information that directly answers the question. For any gap in the sections, write "この情報は知識ファイルの対象範囲外です" — do not infer.
4. Write the answer in this format, staying within 500 tokens (up to 800 for complex questions):

**結論**: Direct answer to the question (1–2 sentences)
- Include specific method names, class names, and approaches
- Do not parrot back the question

**根拠**: Code examples, configuration examples, or spec information that backs the conclusion
- Show code/config examples in code blocks
- Priority: implementation example > configuration example > API spec > conceptual explanation
- If using multiple sections, organize along the implementation flow
- Quote code examples from sections verbatim (do not modify)

**注意点**: Constraints, resource management, common mistakes
- Omit this section if nothing applies

参照: Only sections actually cited in the answer (file.json:sN format, omit category path)

Note: General Java/programming knowledge (try-catch, Bean, getter/setter, etc.) may be used alongside knowledge sections.

## Step 6: Verify answer
Check that all Nablarch-specific claims in answer_text are supported by sections_content.

Extract Nablarch-specific claims (API names, class names, configuration methods, behavior specs, constraints, parameters).
Do NOT extract general Java/programming knowledge.

For each extracted claim, judge:
1. Directly stated in section content → supported
2. Direct paraphrase of section content → supported
3. Attribute/behavior/constraint not explicitly stated → unsupported

If any claim is unsupported, set verify_result = FAIL and record issues. Otherwise verify_result = PASS.

## Step 7: Handle verify result
If PASS: Set final_answer = answer_text.
If FAIL: Re-run Step 5 once with constraint: do not include any of the issues claims in the answer. Save result as final_answer.

## Output
Return a JSON object with:
- answer_text: the generated answer
- verify_result: PASS or FAIL
- issues: list of unsupported claims (empty if PASS)
- final_answer: the verified final answer
- answer_sections_used: array of {ref, reason} for sections cited in the final answer
- answer_sections_unused: array of {ref, reason} for sections read but not used`,
  { schema: SCHEMA_ANSWER }
)

return {
  searchResult,
  sectionsToRead,
  answerResult
}

